from math import gcd

class Solution:
    def maxPoints(self, points: List[List[int]]) -> int:
        n = len(points)
        if n < 3:
            return n
        ans = 0
        for i in range(n):
            x1, y1 = points[i]
            slope = {}
            same = 1
            for j in range(i + 1, n):
                x2, y2 = points[j]
                dx, dy = x2 - x1, y2 - y1
                if dx == 0 and dy == 0:
                    same += 1
                    continue
                g = gcd(dx, dy)
                dx //= g
                dy //= g
                if dx < 0:
                    dx, dy = -dx, -dy
                key = (dx, dy)
                slope[key] = slope.get(key, 0) + 1
            local = same
            for cnt in slope.values():
                local = max(local, cnt + same)
            ans = max(ans, local)
        return ans

